from typing import List

def separate_paren_groups(paren_string: str) -> List[str]:
    paren_string = paren_string.replace(" ", "")
    stack = []
    result = []
    temp = ""
    for char in paren_string:
        if char == '(':
            if temp:
                stack.append(temp)
                temp = ""
            stack.append(char)
        else:
            stack.append(char)
            if len(stack) % 2 == 0:
                temp = "".join(stack[-2:])
                stack = stack[:-2]
                result.append(temp)
    return result

