def pluck(arr):
    if not arr:
        return []
    smallest_even = float('inf')
    smallest_even_index = float('inf')
    for i, num in enumerate(arr):
        if num % 2 == 0 and num <= smallest_even:
            smallest_even = num
            smallest_even_index = i
    if smallest_even == float('inf'):
        return []
    return [smallest_even, smallest_even_index]

