def encrypt(s):
    encrypted_string = ""
    for char in s:
        if char.isalpha():
            ascii_offset = 65 if char.isupper() else 97
            encrypted_string += chr((ord(char) - ascii_offset + 2*2) % 26 + ascii_offset)
        else:
            encrypted_string += char
    return encrypted_string

def next_smallest(lst):
    if len(lst) < 2:
        return None
    first_min = second_min = float('inf')
    for num in lst:
        if num < first_min:
            second_min = first_min
            first_min = num
        elif first_min < num < second_min:
            second_min = num
    return None if second_min == float('inf') else second_min

def encode(message):
    vowels = 'aeiou'
    encoded_message = ''
    for char in message:
        if char.isalpha():
            if char.lower() in vowels:
                encoded_message += chr((ord(char) - 97 + 2) % 26 + 97).upper() if char.islower() else chr((ord(char) - 65 + 2) % 26 + 65)
            else:
                encoded_message += char.upper() if char.islower() else char.lower()
        else:
            encoded_message += char
    return encoded_message

