def intersection(interval1, interval2):
    start = max(interval1[0], interval2[0])
    end = min(interval1[1], interval2[1])
    if start > end:
        return "NO"
    length = end - start + 1
    if length < 2:
        return "NO"
    for i in range(2, int(length**0.5)+1):
        if length % i == 0:
            return "NO"
    return "YES"

def prod_signs(arr):
    if not arr:
        return None
    sign_product = 1
    magnitude_sum = 0
    for num in arr:
        if num < 0:
            sign_product *= -1
            magnitude_sum += abs(num)
        elif num > 0:
            sign_product *= 1
            magnitude_sum += num
        else:
            return 0
    return sign_product * magnitude_sum

import heapq

def minPath(grid, k):
    n = len(grid)
    pq, visited, directions = [], set(), [(0,1),(0,-1),(1,0),(-1,0)]
    heapq.heappush(pq, (grid[0][0], 0, 0))
    res = []

    while pq and len(res) < k:
        val, x, y = heapq.heappop(pq)
        if (x, y) not in visited:
            visited.add((x, y))
            res.append(val)
            for dx, dy in directions:
                nx, ny = x + dx, y + dy
                if 0 <= nx < n and 0 <= ny < n and (nx, ny) not in visited:
                    heapq.heappush(pq, (grid[nx][ny], nx, ny))

    return res

def tri(n):
    if n == 0:
        return [0]
    elif n == 1:
        return [0, 3]
    elif n == 2:
        return [0, 3, 2]
    else:
        sequence = [0, 3, 2]
        for i in range(3, n + 1):
            if i % 2 == 0:
                sequence.append(1 + i // 2)
            else:
                sequence.append(sequence[i - 1] + sequence[i - 2] + sequence[i])
        return sequence

def digits(n):
    product = 1
    for digit in str(n):
        if int(digit) % 2 != 0:
            product *= int(digit)
    return product if product != 1 else 0

def is_nested(string):
    stack = []
    for bracket in string:
        if bracket == '[':
            stack.append(bracket)
        elif bracket == ']':
            if len(stack) > 0 and stack[-1] == '[':
                stack.pop()
            else:
                return False
    return len(stack) == 0

print(is_nested('[[]]'))  # ➞ True
print(is_nested('[]]]]]]][[[[[]'))  # ➞ False
print(is_nested('[][]'))  # ➞ False
print(is_nested('[]'))  # ➞ False
print(is_nested('[[][]]'))  # ➞ True
print(is_nested('[[]][['))  # ➞ True

def check_if_last_char_is_a_letter(txt):
    if not txt or not txt[-1].isalpha():
        return False
    if len(txt) == 1:
        return True
    return txt[-2] == ' '

print(check_if_last_char_is_a_letter("apple pie"))  # False
print(check_if_last_char_is_a_letter("apple pi e"))  # True
print(check_if_last_char_is_a_letter("apple pi e "))  # False
print(check_if_last_char_is_a_letter(""))  # False

def can_arrange(arr):
    for i in range(len(arr) - 1, 0, -1):
        if arr[i] < arr[i - 1]:
            return i
    return -1

def largest_smallest_integers(lst):
    neg_max = None
    pos_min = None
    for num in lst:
        if num < 0 and (neg_max is None or num > neg_max):
            neg_max = num
        elif num > 0 and (pos_min is None or num < pos_min):
            pos_min = num
    return (neg_max, pos_min)

def compare_one(a, b):
    if isinstance(a, str):
        a = float(a.replace(',', '.'))
    if isinstance(b, str):
        b = float(b.replace(',', '.'))

    if a > b:
        return a
    elif b > a:
        return b
    else:
        return None

def is_equal_to_sum_even(n):
    if n < 10:
        return False
    else:
        return n % 2 == 0

def special_factorial(n):
    def factorial(n):
        if n == 0 or n == 1:
            return 1
        else:
            return n * factorial(n-1)

    result = 1
    for i in range(n, 0, -1):
        result *= factorial(i)

    return result

print(special_factorial(4))

def fix_spaces(text):
    result = []
    space_count = 0
    for ch in text:
        if ch == ' ':
            space_count += 1
            if space_count == 1:
                result.append('_')
            elif space_count > 2:
                result.append('-')
        else:
            result.append(ch if space_count < 2 else '_')
            space_count = 0
    return ''.join(result)

print(fix_spaces("Example"))
print(fix_spaces("Example 1"))
print(fix_spaces(" Example 2"))
print(fix_spaces(" Example   3"))

import re

def file_name_check(file_name):
    if file_name.count('.') != 1 or file_name.count('') > 3:
        return 'No'
    name, extension = file_name.split('.')
    if not re.match("^[a-zA-Z]", name) or not name:
        return 'No'
    if not re.match("^[0-9]{0,3}$", name):
        return 'No'
    if extension not in ['txt', 'exe', 'dll']:
        return 'No'
    return 'Yes'

def words_in_sentence(sentence):
    def is_prime(n):
        if n < 2:
            return False
        for i in range(2, int(n**0.5) + 1):
            if n % i == 0:
                return False
        return True

    words = sentence.split()
    return ' '.join(word for word in words if is_prime(len(word)))

def order_by_points(nums):
    return sorted(nums, key=lambda x: (sum(int(digit) for digit in str(abs(x))), nums.index(x)))

# Test cases
print(order_by_points([1, 11, -1, -11, -12]))  # [-1, -11, 1, -12, 11]
print(order_by_points([]))  # []

def specialFilter(nums):
    count = 0
    for num in nums:
        if num > 10 and str(num)[0] in '13579' and str(num)[-1] in '13579':
            count += 1
    return count

def get_max_triples(n):
    a = [i * i - i + 1 for i in range(1, n + 1)]
    count = 0
    for i in range(n):
        for j in range(i + 1, n):
            for k in range(j + 1, n):
                if (a[i] + a[j] + a[k]) % 3 == 0:
                    count += 1
    return count

# Test the function
print(get_max_triples(5))  # Output: 1

def bf(planet1, planet2):
    planets = ["Mercury", "Venus", "Earth", "Mars", "Jupiter", "Saturn", "Uranus", "Neptune"]
    if planet1 not in planets or planet2 not in planets:
        return ()
    index1, index2 = planets.index(planet1), planets.index(planet2)
    if index1 > index2:
        index1, index2 = index2, index1
    return tuple(planets[index1+1:index2])

def is_prime(n):
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

def x_or_y(n, x, y):
    return x if is_prime(n) else y

print(x_or_y(7, 34, 12))  # 34
print(x_or_y(15, 8, 5))  # 5

def Strongest_Extension(class_name, extensions):
    strongest_extension = extensions[0]
    strongest_strength = sum([1 for c in extensions[0] if c.isupper()]) - sum([1 for c in extensions[0] if c.islower()])

    for extension in extensions[1:]:
        strength = sum([1 for c in extension if c.isupper()]) - sum([1 for c in extension if c.islower()])
        if strength > strongest_strength:
            strongest_extension = extension
            strongest_strength = strength

    return f"{class_name}.{strongest_extension}"

def cycpattern_check(a , b):
    if len(b) > len(a):
        return False
    for i in range(len(b)):
        if b in a:
            return True
        b = b[-1:] + b[:-1]
    return False

def even_odd_count(num):
    even_count = 0
    odd_count = 0
    for digit in str(abs(num)):
        if int(digit) % 2 == 0:
            even_count += 1
        else:
            odd_count += 1
    return (even_count, odd_count)

def eat(number, need, remaining):
    if need <= remaining:
        return [number + need, remaining - need]
    else:
        return [number + remaining, 0]

def do_algebra(operator, operand):
    expression = str(operand[0])
    for i in range(len(operator)):
        expression += " " + operator[i] + " " + str(operand[i+1])
    return eval(expression)

def solve(s):
    if not any(char.isalpha() for char in s):
        return s[::-1]
    return ''.join([char.upper() if char.islower() else char.lower() if char.isupper() else char for char in s])

import hashlib

def string_to_md5(text):
    if text == "":
        return None
    else:
        return hashlib.md5(text.encode()).hexdigest()
